#!/usr/bin/env node
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";
import { build } from "rolldown";

const root = dirname(dirname(fileURLToPath(import.meta.url)));
const check = process.argv.includes("--check");
const input = "packages/core/src/code-mode/platform-entry.ts";
const output = "packages/core/src/code-mode/platform-runtime.generated.ts";
const exportName = "CODE_MODE_PLATFORM_RUNTIME_SOURCE";

const bundled = await generateBundle();
const generated = [
  "// Generated by scripts/generate-code-mode-platform-runtime.mjs. Do not edit by hand.",
  `export const ${exportName} =`,
  `  '${singleQuoted(bundled)}' as const;`,
  "",
].join("\n");

if (check) {
  const current = readFileSync(join(root, output), "utf8");
  if (current !== generated) {
    console.error(`${output} is out of date. Run pnpm code-mode:generate-api.`);
    process.exitCode = 1;
  }
} else {
  writeFileSync(join(root, output), generated);
}

async function generateBundle() {
  const bundle = await build({
    input: join(root, input),
    platform: "browser",
    output: {
      format: "iife",
      name: "__caplets_platform_runtime",
    },
  });

  try {
    const chunk = bundle.output.find((item) => item.type === "chunk");
    if (!chunk) {
      throw new Error("Rolldown did not produce a platform runtime chunk.");
    }
    return normalizeBundle(chunk.code);
  } finally {
    await bundle.close?.();
  }
}

function normalizeBundle(value) {
  return value.replace(/\r\n?/gu, "\n").trimEnd();
}

function singleQuoted(value) {
  return value
    .replace(/\\/gu, "\\\\")
    .replace(/'/gu, "\\'")
    .replace(/\n/gu, "\\n")
    .replace(/\t/gu, "\\t");
}
